import redis
from typing import Optional

class RedisCache:
    def __init__(self, host='localhost', port=6379, db=0):
        self.redis_client = redis.Redis(host=host, port=port, db=db)
        self.cluster_nodes = []  # List of Redis cluster nodes (host:port)

    def add_cluster_node(self, node: str) -> None:
        """Add a Redis cluster node to the list."""
        if not isinstance(node, str):
            raise ValueError("Node must be a string")
        try:
            host, port = node.split(":")
            self.cluster_nodes.append((host, int(port)))
        except ValueError as e:
            print(f"Error adding node: {e}")

    def get_cluster_client(self) -> Optional[redis.Redis]:
        """Return a Redis client for the cluster. If no nodes are added, returns None."""
        if not self.cluster_nodes:
            return None
        return redis.Redis(hostlist=self.cluster_nodes)

    def set_session_token(self, user_id: str, token: str, ttl=3600):
        """Set session token in Redis with TTL."""
        self.get_cluster_client().set(f"session:{user_id}", token, ex=ttl)

    def get_session_token(self, user_id: str) -> Optional[str]:
        """Get session token from Redis."""
        return self.get_cluster_client().get(f"session:{user_id}")

    def set_api_key(self, app_name: str, key: str, ttl=3600):
        """Set API key in Redis with TTL."""
        self.get_cluster_client().set(f"api:{app_name}", key, ex=ttl)

    def get_api_key(self, app_name: str) -> Optional[str]:
        """Get API key from Redis."""
        return self.get_cluster_client().get(f"api:{app_name}")

# Example usage:
redis_cache = RedisCache()
